import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.BbQrW5_t.js";const c=JSON.parse('{"title":"第三章 中学教学","description":"","frontmatter":{"title":"第三章 中学教学","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter3.md","filePath":"study/teacher-cert/education-knowledge/chapter3.md","lastUpdated":1783652711000}'),o={name:"study/teacher-cert/education-knowledge/chapter3.md"};function l(h,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第三章-中学教学" tabindex="-1">第三章 中学教学 <a class="header-anchor" href="#第三章-中学教学" aria-label="Permalink to &quot;第三章 中学教学&quot;">​</a></h1><blockquote><p>本章考情：高频大题，约 15-20 分 重点：教学过程规律、教学原则、教学方法</p></blockquote><hr><h2 id="_3-1-教学概述-🔴" tabindex="-1">3.1 教学概述 🔴 <a class="header-anchor" href="#_3-1-教学概述-🔴" aria-label="Permalink to &quot;3.1 教学概述 🔴&quot;">​</a></h2><h3 id="教学的任务" tabindex="-1">教学的任务 <a class="header-anchor" href="#教学的任务" aria-label="Permalink to &quot;教学的任务&quot;">​</a></h3><ol><li>传授系统基础知识（首要任务）🔴</li><li>形成基本技能</li><li>发展智力和体力</li><li>培养品德和审美</li><li>促进个性发展</li></ol><h3 id="教学工作的基本环节-🔴🔴" tabindex="-1">教学工作的基本环节 🔴🔴 <a class="header-anchor" href="#教学工作的基本环节-🔴🔴" aria-label="Permalink to &quot;教学工作的基本环节 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>地位</th><th>要点</th></tr></thead><tbody><tr><td>备课 🔴</td><td>上课的前提</td><td>备教材、备学生、备教法（三备）</td></tr><tr><td>上课 🔴🔴</td><td>中心环节</td><td>好课标准：目标明确、内容正确、方法恰当、结构紧凑</td></tr><tr><td>作业布置与批改</td><td>课堂延续</td><td>量适当、有针对性</td></tr><tr><td>课外辅导</td><td>补充</td><td>因材施教</td></tr><tr><td>学业成绩评价</td><td>检验</td><td>形成性+终结性</td></tr></tbody></table><p><strong>备课的三种计划</strong> 🔴：</p><ol><li>学期教学计划（一学期）</li><li>单元教学计划（一单元）</li><li>课时教学计划（一节课，即教案）</li></ol><hr><h2 id="_3-2-教学过程-🔴🔴🔴" tabindex="-1">3.2 教学过程 🔴🔴🔴 <a class="header-anchor" href="#_3-2-教学过程-🔴🔴🔴" aria-label="Permalink to &quot;3.2 教学过程 🔴🔴🔴&quot;">​</a></h2><h3 id="教学过程的本质" tabindex="-1">教学过程的本质 <a class="header-anchor" href="#教学过程的本质" aria-label="Permalink to &quot;教学过程的本质&quot;">​</a></h3><p>教学过程是一种<strong>特殊的认识过程</strong> 🔴🔴：</p><ul><li>认识的间接性 — 以书本知识为主</li><li>认识的引导性 — 在教师引导下</li><li>认识的简捷性 — 走捷径，不必重复人类探索的全部过程</li></ul><h3 id="教学过程的基本规律-🔴🔴🔴" tabindex="-1">教学过程的基本规律 🔴🔴🔴 <a class="header-anchor" href="#教学过程的基本规律-🔴🔴🔴" aria-label="Permalink to &quot;教学过程的基本规律 🔴🔴🔴&quot;">​</a></h3><p><strong>口诀：舰长直教（间长知交）</strong></p><table tabindex="0"><thead><tr><th>规律</th><th>含义</th><th>教育启示</th><th>判断关键词</th></tr></thead><tbody><tr><td>间接性规律 🔴🔴</td><td>直接经验与间接经验相统一，以间接经验为主</td><td>以书本知识为主，辅以直接经验</td><td>书本、间接、理论联系实际</td></tr><tr><td>发展性规律 🔴🔴</td><td>掌握知识与发展能力相统一</td><td>既要传授知识又要发展能力</td><td>知识+能力、授人以渔</td></tr><tr><td>教育性规律 🔴</td><td>传授知识与思想教育相统一</td><td>教学永远具有教育性（赫尔巴特） 🔴</td><td>教书育人、教学的教育性</td></tr><tr><td>双边性规律 🔴🔴</td><td>教师主导与学生主体相统一</td><td>教师主导+学生主动</td><td>师生互动、教师引导+学生参与</td></tr></tbody></table><p><strong>辨析题高频</strong> 🔴🔴🔴：</p><ol><li>&quot;教学就是传授知识&quot; → ❌ 还包括发展能力、思想教育</li><li>&quot;掌握知识就等于发展了能力&quot; → ❌ 知识不等于能力，需要转化</li><li>&quot;教学永远具有教育性&quot; → ✅ 赫尔巴特名言</li><li>&quot;教师主导与学生的主体地位矛盾&quot; → ❌ 二者统一</li></ol><h3 id="教学过程阶段-🔴" tabindex="-1">教学过程阶段 🔴 <a class="header-anchor" href="#教学过程阶段-🔴" aria-label="Permalink to &quot;教学过程阶段 🔴&quot;">​</a></h3><p><strong>赫尔巴特五段论</strong>：预备→提示→联想→总结→应用</p><p><strong>我国常用阶段</strong>：引发动机→领会知识→巩固知识→运用知识→检查知识</p><hr><h2 id="_3-3-教学原则-🔴🔴🔴" tabindex="-1">3.3 教学原则 🔴🔴🔴 <a class="header-anchor" href="#_3-3-教学原则-🔴🔴🔴" aria-label="Permalink to &quot;3.3 教学原则 🔴🔴🔴&quot;">​</a></h2><blockquote><p>必考简答题或材料分析题</p></blockquote><h3 id="八大教学原则" tabindex="-1">八大教学原则 <a class="header-anchor" href="#八大教学原则" aria-label="Permalink to &quot;八大教学原则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原则</th><th>含义</th><th>关键词</th><th>名言/出处 🔴</th><th>判断材料关键词</th></tr></thead><tbody><tr><td>直观性原则</td><td>通过实物或直观教具使学生获得感性认识</td><td>看得见</td><td>夸美纽斯&quot;一切事物尽量用感官去感知&quot;</td><td>演示、模型、图片、参观</td></tr><tr><td>启发性原则 🔴🔴🔴</td><td>引导学生独立思考，主动学习</td><td>不直接给答案</td><td>孔子&quot;不愤不启，不悱不发&quot; 🔴</td><td>提问、讨论、引导思考</td></tr><tr><td>巩固性原则</td><td>复习已学知识，牢固掌握</td><td>温故知新</td><td>孔子&quot;温故而知新&quot; 🔴</td><td>复习、练习、反复</td></tr><tr><td>循序渐进原则 🔴</td><td>按学科逻辑顺序，由易到难</td><td>逐步深入</td><td>《学记》&quot;学不躐等&quot;&quot;不陵节而施&quot; 🔴</td><td>由简到难、由浅入深</td></tr><tr><td>因材施教原则 🔴</td><td>根据学生差异，区别对待</td><td>不同对待</td><td>朱熹&quot;夫子教人各因其材&quot; 🔴</td><td>分层、针对不同学生</td></tr><tr><td>理论联系实际原则</td><td>学以致用，知行合一</td><td>知行合一</td><td>—</td><td>实践活动、生活实例</td></tr><tr><td>量力性原则</td><td>适应学生发展水平，可接受</td><td>可接受</td><td>墨子&quot;夫智者必量其力所能至&quot;</td><td>难度适中、跳一跳摘桃子</td></tr><tr><td>科学性与思想性统一</td><td>传授科学知识+思想教育</td><td>既教书又育人</td><td>—</td><td>既要科学准确又要思想引导</td></tr></tbody></table><p><strong>口诀</strong>：直启巩循因理量科（直起弓寻因理量科）</p><h3 id="教学原则辨析-🔴🔴" tabindex="-1">教学原则辨析 🔴🔴 <a class="header-anchor" href="#教学原则辨析-🔴🔴" aria-label="Permalink to &quot;教学原则辨析 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>易混点</th><th>区别</th></tr></thead><tbody><tr><td>循序渐进 vs 量力性</td><td>循序渐进 = 按知识逻辑顺序；量力性 = 适应学生接受能力</td></tr><tr><td>直观性 vs 启发性</td><td>直观性 = 让知识可见；启发性 = 让思维活跃</td></tr><tr><td>因材施教 vs 循序渐进</td><td>因材施教 = 针对不同学生；循序渐进 = 按顺序教</td></tr></tbody></table><hr><h2 id="_3-4-教学方法-🔴🔴" tabindex="-1">3.4 教学方法 🔴🔴 <a class="header-anchor" href="#_3-4-教学方法-🔴🔴" aria-label="Permalink to &quot;3.4 教学方法 🔴🔴&quot;">​</a></h2><h3 id="常用教学方法" tabindex="-1">常用教学方法 <a class="header-anchor" href="#常用教学方法" aria-label="Permalink to &quot;常用教学方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>方法</th><th>含义</th><th>适用场景</th></tr></thead><tbody><tr><td>语言传递</td><td>讲授法 🔴</td><td>教师口头系统讲解</td><td>概念、原理</td></tr><tr><td></td><td>谈话法</td><td>师生问答</td><td>启发思维</td></tr><tr><td></td><td>讨论法</td><td>学生分组讨论</td><td>开放性问题</td></tr><tr><td></td><td>读书指导法</td><td>指导学生阅读</td><td>自学能力培养</td></tr><tr><td>直观感知</td><td>演示法</td><td>展示实物或模型</td><td>形象认知</td></tr><tr><td></td><td>参观法</td><td>组织实地参观</td><td>实践体验</td></tr><tr><td>实际训练</td><td>练习法 🔴</td><td>反复操作巩固</td><td>技能训练</td></tr><tr><td></td><td>实验法</td><td>学生动手操作实验</td><td>科学探究</td></tr><tr><td></td><td>实习作业法</td><td>校外实践</td><td>职业教育</td></tr><tr><td>引导探究</td><td>发现法 🔴</td><td>引导学生自主发现</td><td>规律探究</td></tr></tbody></table><p><strong>教学方法选择依据</strong> 🔴：</p><ol><li>教学目的和任务</li><li>课程性质和教材特点</li><li>学生特点</li><li>教学时间、设备、条件</li><li>教师业务水平</li></ol><hr><h2 id="_3-5-教学组织形式-🔴🔴" tabindex="-1">3.5 教学组织形式 🔴🔴 <a class="header-anchor" href="#_3-5-教学组织形式-🔴🔴" aria-label="Permalink to &quot;3.5 教学组织形式 🔴🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>形式</th><th>特点</th><th>创立者/代表</th></tr></thead><tbody><tr><td>个别教学</td><td>最早的形式，教师个别指导</td><td>古代</td></tr><tr><td>班级授课制 🔴🔴🔴</td><td>最基本的形式，固定班级、固定课表</td><td>夸美纽斯《大教学论》🔴</td></tr><tr><td>分组教学</td><td>外部分组+内部分组</td><td>—</td></tr><tr><td>设计教学法</td><td>学生自主决定学习内容和活动</td><td>克伯屈 🔴</td></tr><tr><td>道尔顿制</td><td>自学+答疑，教师不再系统讲授</td><td>柏克赫斯特 🔴</td></tr><tr><td>特朗普制</td><td>大班上课+小班讨论+个人自学</td><td>特朗普</td></tr></tbody></table><p><strong>班级授课制的优缺点</strong> 🔴🔴：</p><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>效率高，大面积培养人才</td><td>不易因材施教</td></tr><tr><td>发挥教师主导作用</td><td>不易发挥学生主体性</td></tr><tr><td>系统性强</td><td>实践性不足</td></tr><tr><td>集体教育效果好</td><td>灵活性不够</td></tr></tbody></table><hr><h2 id="_3-6-教学评价-🔴" tabindex="-1">3.6 教学评价 🔴 <a class="header-anchor" href="#_3-6-教学评价-🔴" aria-label="Permalink to &quot;3.6 教学评价 🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>作用</th></tr></thead><tbody><tr><td>诊断性评价</td><td>教学前摸底</td><td>了解起点</td></tr><tr><td>形成性评价 🔴</td><td>教学过程中</td><td>及时反馈调整</td></tr><tr><td>终结性评价</td><td>教学结束后</td><td>总结性判断</td></tr><tr><td>相对性评价</td><td>与他人比较</td><td>选拔</td></tr><tr><td>绝对性评价</td><td>与标准比较</td><td>达标</td></tr><tr><td>个体内差异评价</td><td>与自己过去比</td><td>进步评价</td></tr></tbody></table><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><h3 id="教学原则口诀" tabindex="-1">教学原则口诀 <a class="header-anchor" href="#教学原则口诀" aria-label="Permalink to &quot;教学原则口诀&quot;">​</a></h3><p><strong>直起弓寻因理量科</strong>：直观、启发、巩固、循序渐进、因材施教、理论联系实际、量力性、科学性与思想性统一</p><h3 id="教学过程规律" tabindex="-1">教学过程规律 <a class="header-anchor" href="#教学过程规律" aria-label="Permalink to &quot;教学过程规律&quot;">​</a></h3><p><strong>舰长直教</strong>：间接性、发展性、教育性、双边性</p><h3 id="简答题必背" tabindex="-1">简答题必背 <a class="header-anchor" href="#简答题必背" aria-label="Permalink to &quot;简答题必背&quot;">​</a></h3><p><strong>教学过程四大规律</strong> 🔴🔴🔴：</p><ol><li>直接经验与间接经验相统一（间接性）</li><li>掌握知识与发展能力相统一（发展性）</li><li>传授知识与思想教育相统一（教育性）</li><li>教师主导与学生主体相统一（双边性）</li></ol><p><strong>启发性原则贯彻要求</strong> 🔴🔴：</p><ol><li>调动学生主动性</li><li>启发独立思考</li><li>让学生动手实践</li><li>发扬教学民主</li></ol>',56)])])}const q=d(o,[["render",l]]);export{c as __pageData,q as default};
